class Solution:
    def sumImbalanceNumbers(self, nums):
        n = len(nums)
        total = 0
        for i in range(n):
            for j in range(i, n):
                sarr = sorted(nums[i:j + 1])
                total += sum(1 for k in range(len(sarr) - 1) if sarr[k + 1] - sarr[k] > 1)
        return total

