class Solution:
    def sumImbalanceNumbers(self, nums):
        n = len(nums)
        total = 0
        for i in range(n):
            seen = [False] * (n + 2)
            cnt = 0
            seen[nums[i]] = True
            for j in range(i + 1, n):
                x = nums[j]
                if not seen[x]:
                    seen[x] = True
                    cnt += 1
                    if x - 1 >= 1 and seen[x - 1]:
                        cnt -= 1
                    if x + 1 <= n and seen[x + 1]:
                        cnt -= 1
                total += cnt
        return total

