var sumImbalanceNumbers = function(nums) {
    const n = nums.length;
    let total = 0;
    for (let i = 0; i < n; i++) {
        const seen = new Array(n + 2).fill(false);
        let cnt = 0;
        seen[nums[i]] = true;
        for (let j = i + 1; j < n; j++) {
            const x = nums[j];
            if (!seen[x]) {
                seen[x] = true;
                cnt++;
                if (x - 1 >= 1 && seen[x - 1]) cnt--;
                if (x + 1 <= n && seen[x + 1]) cnt--;
            }
            total += cnt;
        }
    }
    return total;
};
